    35  func (s *searchHTTPService) doQuery(c *contextmodel.ReqContext) response.Response {
    36          ctx, span := tracer.Start(c.Req.Context(), "searchV2.doQuery")
    37          defer span.End()
    38          searchReadinessCheckResp := s.search.IsReady(ctx, c.GetOrgID())
    39          if !searchReadinessCheckResp.IsReady {
    40                  dashboardSearchNotServedRequestsCounter.With(prometheus.Labels{
    41                          "reason": searchReadinessCheckResp.Reason,
    42                  }).Inc()
    43
    44                  return response.JSON(http.StatusOK, &backend.DataResponse{
    45                          Frames: []*data.Frame{{
    46                                  Name: "Loading",
    47                          }},
    48                          Error: nil,
    49                  })
    50          }
    51
    52          body, err := io.ReadAll(c.Req.Body)
    53          if err != nil {
    54                  return response.Error(http.StatusInternalServerError, "error reading bytes", err)
    55          }
    56
    57          query := &DashboardQuery{}
    58          err = json.Unmarshal(body, query)
    59          if err != nil {
    60                  return response.Error(http.StatusBadRequest, "error parsing body", err)
    61          }
    62
    63          resp := s.search.doDashboardQuery(ctx, c.SignedInUser, c.GetOrgID(), *query)
    64
    65          if resp.Error != nil {
    66                  return response.Error(http.StatusInternalServerError, "error handling search request", resp.Error)
    67          }
    68
    69          if len(resp.Frames) == 0 {
    70                  msg := "invalid search response"
    71                  return response.Error(http.StatusInternalServerError, msg, errors.New(msg))
    72          }
    73
    74          bytes, err := resp.MarshalJSON()
    75          if err != nil {
    76                  return response.Error(http.StatusInternalServerError, "error marshalling response", err)
    77          }
    78
    79          return response.JSON(http.StatusOK, bytes)
    80  }

