    44  func (s *standardStorageService) RegisterHTTPRoutes(storageRoute routing.RouteRegister) {
    45          storageRoute.Get("/list/", routing.Wrap(s.list))
    46          storageRoute.Get("/list/*", routing.Wrap(s.list))
    47          storageRoute.Get("/read/*", routing.Wrap(s.read))
    48          storageRoute.Get("/options/*", routing.Wrap(s.getOptions))
    49
    50          // Write paths
    51          reqGrafanaAdmin := middleware.ReqGrafanaAdmin
    52          storageRoute.Post("/write/*", reqGrafanaAdmin, routing.Wrap(s.doWrite))
    53          storageRoute.Post("/delete/*", reqGrafanaAdmin, routing.Wrap(s.doDelete))
    54          storageRoute.Post("/upload", reqGrafanaAdmin, routing.Wrap(s.doUpload))
    55          storageRoute.Post("/createFolder", reqGrafanaAdmin, routing.Wrap(s.doCreateFolder))
    56          storageRoute.Post("/deleteFolder", reqGrafanaAdmin, routing.Wrap(s.doDeleteFolder))
    57          storageRoute.Get("/config", reqGrafanaAdmin, routing.Wrap(s.getConfig))
    58  }
