    60  func (s *standardStorageService) doWrite(c *contextmodel.ReqContext) response.Response {
    61          scope, path := getPathAndScope(c)
    62          cmd := &WriteValueRequest{}
    63          if err := web.Bind(c.Req, cmd); err != nil {
    64                  return response.Error(http.StatusBadRequest, "bad request data", err)
    65          }
    66          cmd.Path = scope + "/" + path
    67          rsp, err := s.write(c.Req.Context(), c.SignedInUser, cmd)
    68          if err != nil {
    69                  return response.Error(http.StatusBadRequest, "save error", err)
    70          }
    71          return response.JSON(http.StatusOK, rsp)
    72  }
