    74  func (s *standardStorageService) doUpload(c *contextmodel.ReqContext) response.Response {
    75          type rspInfo struct {
    76                  Message string `json:"message,omitempty"`
    77                  Path    string `json:"path,omitempty"`
    78                  Count   int    `json:"count,omitempty"`
    79                  Bytes   int    `json:"bytes,omitempty"`
    80                  Error   bool   `json:"err,omitempty"`
    81          }
    82          rsp := &rspInfo{Message: "uploaded"}
    83
    84          c.Req.Body = http.MaxBytesReader(c.Resp, c.Req.Body, MAX_UPLOAD_SIZE)
    85          if err := c.Req.ParseMultipartForm(MAX_UPLOAD_SIZE); err != nil {
    86                  rsp.Message = fmt.Sprintf("Please limit file uploaded under %s", util.ByteCountSI(MAX_UPLOAD_SIZE))
    87                  rsp.Error = true
    88                  return response.JSON(http.StatusBadRequest, rsp)
    89          }
    90          message := getMultipartFormValue(c.Req, "message")
    91          overwriteExistingFile := getMultipartFormValue(c.Req, "overwriteExistingFile") != "false" // must explicitly overwrite
    92          folder := getMultipartFormValue(c.Req, "folder")
    93
    94          for k, fileHeaders := range c.Req.MultipartForm.File {
    95                  path := getMultipartFormValue(c.Req, k+".path") // match the path with a file
    96                  if len(fileHeaders) > 1 {
    97                          path = ""
    98                  }
    99                  if path == "" && folder == "" {
   100                          rsp.Message = "please specify the upload folder or full path"
   101                          rsp.Error = true
   102                          return response.JSON(http.StatusBadRequest, rsp)
   103                  }
   104
   105                  for _, fileHeader := range fileHeaders {
   106                          // restrict file size based on file size
   107                          // open each file to copy contents
   108                          file, err := fileHeader.Open()
   109                          if err != nil {
   110                                  return response.Error(http.StatusInternalServerError, "Internal Server Error", err)
   111                          }
   112                          err = file.Close()
   113                          if err != nil {
   114                                  return response.Error(http.StatusInternalServerError, "Internal Server Error", err)
   115                          }
   116                          data, err := io.ReadAll(file)
   117                          if err != nil {
   118                                  return response.Error(http.StatusInternalServerError, "Internal Server Error", err)
   119                          }
   120
   121                          if path == "" {
   122                                  path = folder + "/" + fileHeader.Filename
   123                          }
   124
   125                          entityType := EntityTypeJSON
   126                          mimeType := http.DetectContentType(data)
   127                          if strings.HasPrefix(mimeType, "image") || strings.HasSuffix(path, ".svg") {
   128                                  entityType = EntityTypeImage
   129                          }
   130
   131                          err = s.Upload(c.Req.Context(), c.SignedInUser, &UploadRequest{
   132                                  Contents:              data,
   133                                  EntityType:            entityType,
   134                                  Path:                  path,
   135                                  OverwriteExistingFile: overwriteExistingFile,
   136                                  Properties: map[string]string{
   137                                          "message": message, // the commit/changelog entry
   138                                  },
   139                          })
   140
   141                          if err != nil {
   142                                  return response.Error(UploadErrorToStatusCode(err), err.Error(), err)
   143                          }
   144                          rsp.Count++
   145                          rsp.Bytes += len(data)
   146                          rsp.Path = path
   147                  }
   148          }
   149
   150          return response.JSON(http.StatusOK, rsp)
   151  }
