   161  func (s *standardStorageService) read(c *contextmodel.ReqContext) response.Response {
   162          // full path is api/storage/read/upload/example.jpg, but we only want the part after read
   163          scope, path := getPathAndScope(c)
   164          file, err := s.Read(c.Req.Context(), c.SignedInUser, scope+"/"+path)
   165          if err != nil {
   166                  return response.Error(http.StatusBadRequest, "cannot call read", err)
   167          }
   168
   169          if file == nil || file.Contents == nil {
   170                  return response.Error(http.StatusNotFound, "file does not exist", err)
   171          }
   172
   173          // set the correct content type for svg
   174          if strings.HasSuffix(path, ".svg") {
   175                  c.Resp.Header().Set("Content-Type", "image/svg+xml")
   176          }
   177          return response.Respond(200, file.Contents)
   178  }
