   140  func RoleAppPluginAuth(accessControl ac.AccessControl, ps pluginstore.Store, logger log.Logger) func(c *contextmodel.ReqContext) {
   141          return func(c *contextmodel.ReqContext) {
   142                  pluginID := web.Params(c.Req)[":id"]
   143                  p, exists := ps.Plugin(c.Req.Context(), pluginID)
   144                  if !exists {
   145                          // The frontend will handle app not found appropriately
   146                          return
   147                  }
   148
   149                  permitted := true
   150                  path := normalizeIncludePath(c.Req.URL.Path)
   151                  hasAccess := ac.HasAccess(accessControl, c)
   152                  for _, i := range p.Includes {
   153                          if i.Type != "page" {
   154                                  continue
   155                          }
   156
   157                          u, err := url.Parse(i.Path)
   158                          if err != nil {
   159                                  logger.Error("failed to parse include path", "pluginId", pluginID, "include", i.Name, "err", err)
   160                                  continue
   161                          }
   162
   163                          if normalizeIncludePath(u.Path) == path {
   164                                  if i.RequiresRBACAction() && !hasAccess(pluginaccesscontrol.GetPluginRouteEvaluator(pluginID, i.Action)) {
   165                                          logger.Debug("Plugin include is covered by RBAC, user doesn't have access", "plugin", pluginID, "include", i.Name)
   166                                          permitted = false
   167                                          break
   168                                  } else if !i.RequiresRBACAction() && !c.HasUserRole(i.Role) {
   169                                          permitted = false
   170                                          break
   171                                  }
   172                          }
   173                  }
   174
   175                  if !permitted {
   176                          accessForbidden(c)
   177                          return
   178                  }
   179          }
   180  }
   181
   182  func normalizeIncludePath(p string) string {
   183          return strings.TrimPrefix(filepath.Clean(p), "/")
   184  }
