   235  // SnapshotPublicModeOrCreate creates a middleware that allows access
   236  // if snapshot public mode is enabled or if user has creation permission.
   237  func SnapshotPublicModeOrCreate(cfg *setting.Cfg, ac2 ac.AccessControl) web.Handler {
   238          return func(c *contextmodel.ReqContext) {
   239                  if cfg.SnapshotPublicMode {
   240                          return
   241                  }
   242
   243                  if !c.IsSignedIn {
   244                          notAuthorized(c)
   245                          return
   246                  }
   247
   248                  ac.Middleware(ac2)(ac.EvalPermission(dashboards.ActionSnapshotsCreate))
   249          }
   250  }
