    79  // GET /api/access-control/users/permissions/search
    80  func (api *AccessControlAPI) searchUsersPermissions(c *contextmodel.ReqContext) response.Response {
    81          ctx, span := tracer.Start(c.Req.Context(), "accesscontrol.api.searchUsersPermissions")
    82          defer span.End()
    83
    84          searchOptions := ac.SearchOptions{
    85                  ActionPrefix: c.Query("actionPrefix"),
    86                  Action:       c.Query("action"),
    87                  Scope:        c.Query("scope"),
    88          }
    89
    90          // namespacedId is the typed identifier of an identity
    91          // it is specified using user/service account IDs or UIDs (ex: user:3, service-account:4, user:adisufjf93e9sd)
    92          if typedID := c.Query("namespacedId"); typedID != "" {
    93                  userID, err := api.ComputeUserID(ctx, c.Query("namespacedId"))
    94                  if err != nil {
    95                          if errors.Is(err, user.ErrUserNotFound) {
    96                                  return response.JSON(http.StatusBadRequest, err.Error())
    97                          }
    98                          return response.JSON(http.StatusInternalServerError, err.Error())
    99                  }
   100
   101                  searchOptions.UserID = userID
   102          }
   103
   104          // Validate inputs
   105          if searchOptions.ActionPrefix != "" && searchOptions.Action != "" {
   106                  return response.JSON(http.StatusBadRequest, "'action' and 'actionPrefix' are mutually exclusive")
   107          }
   108
   109          if searchOptions.UserID <= 0 && searchOptions.ActionPrefix == "" && searchOptions.Action == "" {
   110                  return response.JSON(http.StatusBadRequest, "at least one search option must be provided")
   111          }
   112
   113          // Compute metadata
   114          permissions, err := api.Service.SearchUsersPermissions(ctx, c.SignedInUser, searchOptions)
   115          if err != nil {
   116                  return response.Error(http.StatusInternalServerError, "could not get org user permissions", err)
   117          }
   118
   119          permsByAction := map[int64]map[string][]string{}
   120          for userID, userPerms := range permissions {
   121                  permsByAction[userID] = ac.Reduce(userPerms)
   122          }
   123
   124          return response.JSON(http.StatusOK, permsByAction)
   125  }
