   127  func (api *AccessControlAPI) ComputeUserID(ctx context.Context, typedID string) (int64, error) {
   128          if typedID == "" {
   129                  return -1, nil
   130          }
   131
   132          typ, idStr, err := claims.ParseTypeID(typedID)
   133          if err != nil {
   134                  return 0, err
   135          }
   136
   137          if !claims.IsIdentityType(typ, claims.TypeUser, claims.TypeServiceAccount) {
   138                  return 0, fmt.Errorf("invalid type: %s", typ)
   139          }
   140
   141          id, err := strconv.ParseInt(idStr, 10, 64)
   142          if err == nil {
   143                  return id, nil
   144          }
   145
   146          user, err := api.userSvc.GetByUID(ctx, &user.GetUserByUIDQuery{UID: idStr})
   147          if err != nil {
   148                  return 0, err
   149          }
   150
   151          return user.ID, nil
   152  }

