    48          if err := web.Bind(c.Req, &cmd); err != nil {
    49                  return response.Err(shorturls.ErrShortURLBadRequest.Errorf("bad request data: %w", err))
    50          }
    51          hs.log.Debug("Received request to create short URL", "path", cmd.Path)
    52          shortURL, err := hs.ShortURLService.CreateShortURL(c.Req.Context(), c.SignedInUser, cmd)
    53          if err != nil {
    54                  return response.Err(err)
    55          }
    56
    57          shortURLDTO := hs.ShortURLService.ConvertShortURLToDTO(shortURL, hs.Cfg.AppURL)
    58          c.Logger.Debug("Created short URL", "url", shortURLDTO.URL)
