    69
    70          shortURL, err := hs.ShortURLService.GetShortURLByUID(c.Req.Context(), c.SignedInUser, shortURLUID)
    71          if err != nil {
    72                  // If we didn't get the URL for whatever reason, we redirect to the
    73                  // main page, otherwise we get into an endless loops of redirects, as
    74                  // we would try to redirect again.
    75                  if shorturls.ErrShortURLNotFound.Is(err) {
    76                          hs.log.Debug("Not redirecting short URL since not found", "uid", shortURLUID)
    77                          c.Redirect(hs.Cfg.AppURL, http.StatusPermanentRedirect)
    78                          return
    79                  }
